import React, { Component } from 'react';
import { withRouter, Link } from 'react-router-dom';
import s from './Landing.module.scss';

import imgHeader from './media/header-5.jpg';
import arrowDown from './media/arrow_down.svg';

class Landing extends Component {

    constructor(props) {
        super(props);
        this.state = {

        };
    }

    render() {
        return (
            <>
            <header className={[s['mheader'], "g-width"].join(' ')}>
                <div className={s['mheader__inner']}>
                    <div className={s['mh-about']}>
                        <div className={s['mh-about__box']}>
                            <h2>Share your art.</h2>
                            <p>Unveil yourself.</p>
                            <Link to="/signup" className="bs-btn bs-btn--primary bs-btn--rounded">Join community</Link>
                        </div>
                    </div>
                    <div className={s['mh-image']}>
                        <img src={imgHeader}/>
                    </div>
                </div>
                <div className={s['mheader__discover']}>
                    <p>discover</p>
                    <img src={arrowDown}/>
                </div>
            </header>
            </>
        )
    }
}

export default withRouter(Landing);
